const cfg = $('Konfiguration').first().json;
const docs = $json.results || [];

function tagIds(tags) {
  return (tags || [])
    .map(t => {
      if (typeof t === 'number') return t;
      if (typeof t === 'string') return Number(t);
      if (typeof t === 'object' && t !== null) return Number(t.id ?? t.pk);
      return null;
    })
    .filter(Boolean);
}

const filtered = docs.filter(doc => {
  const tags = tagIds(doc.tags);

  // NICHT verarbeiten, wenn bereits bezahlt
  if (tags.includes(Number(cfg.paperless_paid_tag_id))) {
    return false;
  }

  // Verarbeiten, wenn Rechnung und Zahlung unsicher
  if (tags.includes(Number(cfg.paperless_unsure_tag_id))) {
    return true;
  }

  // Optional: auch noch offene Zahlungen verarbeiten
  if (tags.includes(Number(cfg.paperless_open_tag_id))) {
    return true;
  }

  // Neue Rechnungen ohne Bezahlt-Tag auch verarbeiten
  return true;
});

return filtered.map(doc => ({ json: doc }));

const doc = $json;

return [{
  json: {
    paperless_id: doc.id,
    paperless_title: doc.title || '',
    original_filename: doc.original_filename || '',
    created: doc.created || null,
    added: doc.added || null,
    content: doc.content || '',
    existing_tags: doc.tags || [],
    correspondent: doc.correspondent || null,
    document_type: doc.document_type || null
  }
}];

const base = $('Rechnungstext vorbereiten').first().json;

let raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.output_text ||
  $json.output ||
  $json.text ||
  $json.message?.content ||
  $json.choices?.[0]?.message?.content ||
  '{}';

// Falls output ein Array/Objekt ist
if (Array.isArray(raw)) {
  raw = raw?.[0]?.content?.[0]?.text || JSON.stringify(raw);
}

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    is_invoice: false,
    creditor_name: null,
    invoice_number: null,
    customer_number: null,
    amount_total: null,
    currency: "EUR",
    due_date: null,
    invoice_date: null,
    iban: null,
    bic: null,
    payment_reference: null,
    suggested_firefly_search_terms: [],
    confidence: 0,
    reason: "ChatGPT-Antwort konnte nicht als JSON gelesen werden. Raw: " + raw.slice(0, 500)
  };
}

parsed.paperless_id = base.paperless_id;
parsed.paperless_title = base.paperless_title;
parsed.original_filename = base.original_filename;
parsed.existing_tags = base.existing_tags || [];

return [
  {
    json: parsed
  }
];

// Rechnung aus KI-Analyse
const invoice = $('FinTS Suchparameter bauen').first().json;

// FinTS Transaktionen (Array direkt)
const txList = $input.first().json;
const transactions = Array.isArray(txList) ? txList : [];

const invoiceAmount = parseFloat(invoice.amount_total || 0);
const creditor = (invoice.creditor_name || '').toLowerCase();
const invoiceNum = (invoice.invoice_number || '').toLowerCase();
const payRef = (invoice.payment_reference || '').toLowerCase();
const invoiceIban = (invoice.iban || '').replace(/\s/g, '').toLowerCase();

const candidates = [];

for (const tx of transactions) {
  if (tx.amount >= 0) continue; // Nur Ausgaben
  const txAmount = Math.abs(tx.amount);
  const txName = (tx.applicant_name || '').toLowerCase();
  const txPurpose = (tx.purpose || '').toLowerCase();
  const txIban = (tx.iban || '').replace(/\s/g, '').toLowerCase();

  let score = 0;

  // Betrag passt (±10%)
  if (invoiceAmount > 0) {
    const diff = Math.abs(txAmount - invoiceAmount) / invoiceAmount;
    if (diff < 0.05) score += 40;
    else if (diff < 0.10) score += 20;
  }

  // Gläubiger im Namen
  const creditorWords = creditor.split(/\s+/).filter(w => w.length > 3);
  for (const word of creditorWords) {
    if (txName.includes(word) || txPurpose.includes(word)) score += 15;
  }

  // Rechnungsnummer im Verwendungszweck
  if (invoiceNum && txPurpose.includes(invoiceNum)) score += 35;

  // Zahlungsreferenz
  if (payRef && txPurpose.includes(payRef)) score += 30;

  // IBAN-Match
  if (invoiceIban && invoiceIban.length > 10 && txIban === invoiceIban) score += 25;

  if (score >= 20) {
    candidates.push({
      score,
      date: tx.date,
      amount: tx.amount,
      applicant_name: tx.applicant_name,
      purpose: (tx.purpose || '').substring(0, 100),
      iban: tx.iban
    });
  }
}

candidates.sort((a, b) => b.score - a.score);
const best = candidates[0] || null;

return [{
  json: {
    invoice,
    best_match: best,
    all_candidates: candidates.slice(0, 3),
    match_found: best !== null && best.score >= 35
  }
}];

// ChatGPT-Text holen
const raw = $json.output?.[0]?.content?.[0]?.text;

if (!raw) {
  throw new Error('Kein ChatGPT output[0].content[0].text gefunden');
}

// JSON aus ChatGPT parsen
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error('ChatGPT-Antwort ist kein gültiges JSON: ' + raw);
}

// Status normalisieren
const status = String(parsed.status || '').trim().toLowerCase();

// Bezahlt-Logik
const is_paid = status === 'bezahlt';

// Optional: Rechnung aus vorherigem Node holen
const invoice = $('KI Ergebnis normalisieren').first().json.invoice || {};

// Ergebnis sauber zurückgeben
return [
  {
    json: {
      ...$json,

      status,
      is_paid,

      confidence: parsed.confidence ?? 0,
      matched_transaction_id: parsed.matched_transaction_id ?? null,
      matched_date: parsed.matched_date ?? null,
      matched_amount: parsed.matched_amount ?? null,
      reason: parsed.reason ?? '',

      todo_title: parsed.todo_title || '',
      todo_description: parsed.todo_description || '',
      telegram_message: parsed.telegram_message || '',

      invoice,

      parsed_result: parsed
    }
  }
];

